// Revisión técnica solar con cascada de proveedores: Groq (gratis) → Gemini (gratis) → Claude Haiku (paga).
// Env vars opcionales (usar la primera disponible):
//   GROQ_API_KEY                       → Groq llama-3.3-70b-versatile (gratis, alto rate limit)
//   GEMINI_API_KEY | GOOGLE_AI_KEY     → Google Gemini 2.0 Flash (gratis hasta cuota)
//   ANTHROPIC_API_KEY                  → Claude Haiku 4.5 (paga, fallback de calidad)
// Input body: { context: 'review'|'sizing'|'explain', payload: {...} }

const src = $input.first().json;
const body = src.body || src;
const context = (body.context || 'review').toString();
const payload = body.payload || {};

// Acceso tolerante a $env: el task runner puede denegarlo (TypeError en getter).
const safeEnv = (k) => { try { return $env[k]; } catch (_) { return null; } };
const GROQ = safeEnv('GROQ_API_KEY');
// Acepta el alias GOOGLE_AI_KEY (nombre histórico en Railway de SolarHub) además del estándar GEMINI_API_KEY.
const GEMINI = safeEnv('GEMINI_API_KEY') || safeEnv('GOOGLE_AI_KEY');
const CLAUDE = safeEnv('ANTHROPIC_API_KEY');

if (!GROQ && !GEMINI && !CLAUDE) {
  return [{ json: { ok: false, reason: 'missing_env', detail: 'Ninguna API key configurada. Define al menos una de: GROQ_API_KEY, GEMINI_API_KEY (o GOOGLE_AI_KEY), ANTHROPIC_API_KEY.' } }];
}

const system = 'Eres un ingeniero eléctrico especializado en sistemas solares fotovoltaicos en Colombia. Conoces RETIE, CREG 038/2014, CREG 174/2021 (AGPE), Ley 1715, estándares NEC/IEC. Analiza el dimensionamiento que te envía el cotizador y devuelve observaciones concretas, accionables y técnicas. Usa español neutro.';

// Esquema de campos que el frontend puede aplicar automáticamente.
// El modelo debe proponer 'actions' SOLO con field/value de este listado.
const applyableSchema = `Campos aplicables y valores válidos:\n\n- systemType: 'on-grid' | 'hybrid' | 'off-grid'\n- battQty: integer 1..12 (SOLO si systemType in {hybrid, off-grid})\n- busVoltage: 12 | 24 | 48 (SOLO si systemType in {hybrid, off-grid})\n- backupHours: 2 | 4 | 6 | 8 | 12 | 24 (SOLO si systemType == 'hybrid')\n- autonomyDays: 1 | 2 | 3 (SOLO si systemType == 'off-grid')\n- criticalPct: 25 | 50 | 75 | 100 (SOLO si systemType == 'hybrid')\n- acometida: 'monofasico' | 'bifasico' | 'trifasico'\n- availableArea: number en m² > 0\n- wantsExcedentes: boolean (true = inscribir AGPE para vender excedentes)\n\nCAMPOS NO APLICABLES (NUNCA propongas estos):\n- monthlyKwh (consumo del usuario, viene de su factura — NO se ajusta)\n- IDs de panel/inversor/batería (el frontend no aplica IDs de catálogo)`;

const userPrompt = `Contexto: ${context}\n\nSistema a revisar (JSON):\n${JSON.stringify(payload, null, 2)}\n\n${applyableSchema}\n\nDevuelve SOLO JSON válido con esta forma exacta (sin markdown, sin texto adicional):\n{\n  \"summary\": string,\n  \"findings\": string[],\n  \"warnings\": string[],\n  \"suggestions\": string[],\n  \"actions\": [{ \"field\": string, \"value\": any, \"label\": string, \"reason\": string }]\n}\n\n═══ REGLAS DURAS DE COHERENCIA (no negociables) ═══\n\n[RD-1] systemType — decisión arquitectónica del usuario:\n  • off-grid: predio SIN red disponible (zona rural aislada). NUNCA propongas cambiar systemType desde off-grid — sería físicamente imposible.\n  • on-grid: tiene red, sin baterías. Solo propón cambio a 'hybrid' si hay evidencia EXPLÍCITA de necesidad de respaldo (backupHours>0 declarado, mención de cortes frecuentes, cargas críticas). NO basta con 'sería bueno tener baterías'.\n  • hybrid: tiene red + baterías. No propongas regresar a otros tipos.\n  ADICIONAL: si systemType=='on-grid' Y la cobertura (coverage%) es <100%, NUNCA sugieras hybrid. El sistema está subdimensionado: la prioridad es ampliar paneles, no agregar baterías a algo que ni siquiera cubre el consumo.\n\n[RD-2] wantsExcedentes (AGPE) requiere DOS condiciones simultáneas:\n  (a) Con red — NUNCA si systemType=='off-grid'.\n  (b) Generación REAL excedente — NUNCA si monthlyProdKwh ≤ monthlyKwh. Sin excedentes no hay nada que vender. Cobertura <100% ⇒ sistema subdimensionado, prioriza ampliar antes que inscribir AGPE.\n  Solo proponlo cuando coverage>100% Y el usuario aún no marcó wantsExcedentes:true.\n  CRÍTICO: si payload.wantsExcedentes==true (el usuario YA decidió inscribirse en AGPE), está PROHIBIDO incluir cualquier sugerencia tipo \"considerar AGPE\", \"inscribirse en programa AGPE\", \"vender excedentes\". Eso NO es mejora, es redundancia. En cambio, en findings[] DEBES cuantificar el beneficio usando payload.agpeBenefit: cita ingresoExcedentesCopYear, totalAnualCop, xmSpotCopPerKwh y excedentesKwhYear (ej: \"Inscripción AGPE acertada: con 1.200 kWh/mes excedentes a 280 COP/kWh bolsa XM, ingreso estimado de $4'032.000/año además de ahorro por autoconsumo\"). El objetivo es REFORZAR la decisión con números, no re-sugerirla.\n\n[RD-3] availableArea — declaración del usuario sobre su techo:\n  • NUNCA reducir el área disponible (no se 'optimiza' a la baja).\n  • Solo proponer cambio si actual es 0/null o claramente irreal (ej: 5 m² declarados con 20 paneles requeridos).\n  • NUNCA inflar a valores >1000 m² salvo evidencia clara en el payload.\n\n[RD-4] Campos dependientes de systemType — respeta estrictamente el dominio:\n  • battQty, busVoltage: SOLO si systemType in {hybrid, off-grid}. Nunca en on-grid.\n  • backupHours, criticalPct: SOLO si systemType=='hybrid'.\n  • autonomyDays: SOLO si systemType=='off-grid'.\n  Si propones cambiar systemType en la misma respuesta, NO incluyas estos campos en el mismo lote — el frontend aplica un cambio por vez.\n\n[RD-5] acometida — RETIE Sec. 240, solo escala según potencia AC:\n  • Solo cambiar a 'trifasico' si la potencia del sistema (result.kwp) es ≥10 kW o si el usuario tiene cargas trifásicas declaradas.\n  • NUNCA bajar de trifasico a bifasico/monofasico — la acometida instalada es realidad física.\n  • NO propongas 'monofasico' salvo cargas <3 kW en off-grid.\n\n[RD-6] busVoltage — solo escalar hacia arriba según potencia DC:\n  • kWp <2: 12 V o 24 V aceptable.\n  • kWp 2–5: 24 V mínimo, 48 V recomendado.\n  • kWp >5: 48 V obligatorio.\n  • NUNCA propongas BAJAR el bus (ej: 48→24); solo subir si la potencia lo justifica y el actual es insuficiente.\n\n[RD-7] No propongas valores IGUALES al actual — desperdicia espacio del lote. Antes de emitir cada action, verifica que el value propuesto sea distinto del valor que está en el payload.\n\n[RD-8] monthlyKwh, IDs de catálogo y otros campos no listados — NUNCA los propongas en actions[]. El consumo del usuario viene de su factura, no se ajusta. Si quieres mencionar 'verificar consumo', hazlo SOLO en suggestions, no en actions.\n\n═══ ANÁLISIS TÉCNICO REQUERIDO (revisa cada bloque del payload) ═══\n\nUsa los datos en payload.layout, payload.panel, payload.inverter y payload.siteFactors para generar findings/warnings TÉCNICOS, no genéricos. Cita los valores numéricos del payload en cada observación. Bloques a evaluar:\n\n[T-1] Configuración de strings (payload.layout):\n  • stringVocCold vs vocMax: si vocCold > 0.95×vocMax es alerta (margen <5%), si > vocMax es ERROR (RETIE NEC 690.7 — Vdc_max excedido en frío). Sugiere reducir paneles por string.\n  • stringVmpHot vs mpptMin: si stringVmpHot < mpptMin → MPPT no engancha al mediodía cuando los paneles calientan. Sugiere aumentar paneles por string o cambiar inversor.\n  • stringVmpStc vs mpptMax: si excede el techo MPPT, el inversor clipea — pierde producción.\n  • currentPerMppt vs idcMax: si > idcMax es ERROR (corriente DC supera entrada del inversor); si > 0.9×idcMax sugiere reducir strings paralelos.\n  • stringsPerMppt > 2: requiere combinador con fusibles por string (NEC 690.9). Mencionar.\n  • Si layout.errors o layout.warnings traen contenido, ESCÁLALOS a warnings/findings con cita exacta.\n\n[T-2] Compatibilidad eléctrica panel ↔ inversor:\n  • Coeficientes de temperatura del panel (tempCoeffVoc, tempCoeffPmax) vs clima del sitio (PSH, lat, hotTempC implícito).\n  • Tipo de celda (cellType: PERC/HJT/TopCon) vs temperatura ambiente — HJT/TopCon mejor en clima cálido por menor coef negativo.\n  • Eficiencia del panel (eff %) vs área disponible — paneles >21% eficientes liberan techo para más kWp.\n\n[T-3] DC/AC ratio (payload.result.dcAcRatio):\n  • on-grid óptimo 1.10-1.35; hybrid 1.00-1.25; off-grid 0.95-1.15.\n  • Si fuera de rango → finding técnico (ratio bajo desperdicia inversor; ratio alto clipea).\n\n[T-4] Sitio (payload.siteFactors):\n  • shadeIndex < 0.9: sombras significativas, considerar optimizadores DC o microinversores.\n  • roofTiltDeg muy alejado de la latitud → recomendar estructura inclinada.\n  • roofAzimuthDeg distinto de norte (180°) en hemisferio sur → cita pérdida estimada y sugerir orientación.\n\n[T-5] Banco de baterías (solo si hybrid u off-grid):\n  • payload.battery.totalKwh vs payload.storageReqKwh: si banco < requerido, sugerir aumentar battQty (un valor concreto), NO simplemente \"más autonomía\".\n  • payload.busVoltage vs payload.battery.voltage: que la combinación serie/paralelo dé un múltiplo limpio (ej: 4× 12V = 48V bus). Si battQty no es múltiplo coherente, hay baterías sobrantes.\n  • Tipo de batería: LFP (LiFePO4) preferible a Pb-ácido para ciclado profundo > 80% DoD.\n  • NUNCA sugieras aumentar autonomyDays/backupHours por defecto. SOLO si payload.storageReqKwh excede el banco actual O si las cargas críticas declaradas lo justifican. Si el banco YA cubre la demanda, NO toques la autonomía.\n\n[T-6] Inversor:\n  • Si payload.result.noInverter == true (no hay inversor compatible en stock), warning crítico: "consultar stock con ALEBAS antes de la propuesta".\n  • Phase del inversor vs acometida del cliente: si payload.inverter.phase=3 y acometida=bifasico (o viceversa) → ERROR de compatibilidad de salida AC.\n  • Inversores con offGridCapable=false NO sirven en off-grid puro.\n\n[T-7] Validación financiera de excedentes (cuando payload.agpeBenefit existe):\n  • Si payload.wantsExcedentes==true Y payload.agpeBenefit.gridExport==true: incluye un finding numérico que valide la decisión. Cita: excedentesKwhYear (kWh/año a vender), priceExcedentesCopPerKwh (COP/kWh recibidos), ingresoExcedentesCopYear (COP/año por venta), ahorroAutoconsumoCopYear (COP/año por autoconsumo), totalAnualCop (suma). Si xmSpotCopPerKwh existe, menciona que el precio se ajusta al promedio de bolsa XM (xmSpotPeriodDays días).\n  • Si payload.budget.roi existe, contrasta con totalAnualCop para validar coherencia del payback.\n  • Si excedentesKwhYear/12 > monthlyKwh*0.5 (más del 50% del consumo se exporta), añade finding de oportunidad: el sistema tiene capacidad ociosa relevante (potencial para terceros/comunidad energética/ampliación).\n  • Verificación cruzada: result.annualProdKwh debe ≈ autoConsumedKwhYear + excedentesKwhYear; si difieren >10% advierte inconsistencia en findings.\n  • Estos datos son para REFORZAR la decisión del usuario con cifras, NUNCA para contradecirla. Y NUNCA generan actions[] (RD-2 lo prohíbe cuando wantsExcedentes ya es true).\n\n═══ ESTRUCTURA DE LA RESPUESTA ═══\n\n- summary: 1-2 frases ejecutivas con el veredicto técnico (no comercial).\n- findings: 3-6 observaciones técnicas que CITEN valores del payload (Voc, Vmp, corrientes, ratios, márgenes). Cada finding debe ser específico y verificable, no genérico. Si no hay datos eléctricos completos (panel.voc==null o inverter.vocMax==null), menciona en warnings que falta caracterizar el equipo en el catálogo CEC.\n- warnings: alertas críticas con cita normativa (RETIE Sec. 240/250, NEC 690.7/690.8, IEC 61730, CREG 174/2021). Vacío si todo conforme.\n- suggestions: 3-5 recomendaciones técnicas extensas en lenguaje natural. Cada una debe explicar QUÉ hacer y POR QUÉ desde la ingeniería, no solo "considerar X". Pueden incluir items que NO sean acciones aplicables (ej: optimizadores DC, cambio de cellType, ampliación de combinador). Para off-grid, enfócate en gestión de cargas, autonomía REAL requerida, dump load para excedentes, NO en AGPE/red.\n- actions (CRÍTICO): por cada suggestion que SÍ pueda traducirse a un campo aplicable Y que respete las RD-1 a RD-8, agrega un objeto. Vacío si la config ya está bien técnicamente o si las suggestions son sólo informativas/de hardware.\n\nEjemplos de mapeo válido suggestion → action:\n  • on-grid con cobertura >150% Y wantsExcedentes:false: action = { field: \"wantsExcedentes\", value: true, label: \"Inscribir AGPE\", reason: <breve cita coverage% como justificación> }\n  • on-grid con backupHours>0 declarado por usuario: action = { field: \"systemType\", value: \"hybrid\", label: \"Cambiar a híbrido\", reason: <breve> }\n  • hybrid u off-grid con banco subdimensionado: action = { field: \"battQty\", value: N, label: \"Banco de N baterías\", reason: <breve> }\n  • hybrid u off-grid con bus 24V y kWp>5: action = { field: \"busVoltage\", value: 48, label: \"Bus 48 V DC\", reason: <breve> }\n  • availableArea==null o irreal y techo Google insuficiente: action = { field: \"availableArea\", value: <m²-real>, label: \"Área techo\", reason: <breve> }\n  • kWp>10 con acometida bifasico: action = { field: \"acometida\", value: \"trifasico\", label: \"Acometida trifásica\", reason: <breve> }\n  • off-grid con autonomía 1 día: action = { field: \"autonomyDays\", value: 2 o 3, label: \"Autonomía N días\", reason: <breve> }\n\nEjemplos PROHIBIDOS (no los devuelvas):\n  ✗ off-grid → systemType:'hybrid' (viola RD-1, no hay red)\n  ✗ on-grid cobertura 60% → systemType:'hybrid' (viola RD-1 ampliado: primero ampliar paneles)\n  ✗ off-grid → wantsExcedentes:true (viola RD-2a)\n  ✗ on-grid cobertura 13% → wantsExcedentes:true (viola RD-2b: no hay excedentes)\n  ✗ availableArea: 60 → 50 (viola RD-3, reducir)\n  ✗ on-grid → battQty:N (viola RD-4, no hay baterías en on-grid)\n  ✗ on-grid → autonomyDays:2 (viola RD-4, autonomyDays solo off-grid)\n  ✗ off-grid → backupHours:8 (viola RD-4, backupHours solo hybrid)\n  ✗ trifasico → bifasico (viola RD-5, no se baja)\n  ✗ kWp 3, busVoltage 24 → 12 (viola RD-6, no se baja)\n  ✗ kWp 8, busVoltage 24 → 48 ✓ (válido — kWp>5 exige 48 V)\n  ✗ acometida actual 'bifasico' → bifasico (viola RD-7, mismo valor)\n  ✗ monthlyKwh: 500 → 600 (viola RD-8, no se modifica)\n\n- 'label' ≤60 chars, 'reason' ≤140 chars y debe citar el dato del payload que justifica el cambio.\n- NO inventes IDs de catálogo (panel/inversor/batería); el frontend NO los aplica.\n- Trabaja solo con los datos del payload.`;

function extractJson(text) {
  if (!text) return null;
  const m = text.match(/\{[\s\S]*\}/);
  if (!m) return null;
  try { return JSON.parse(m[0]); } catch (_) { return null; }
}

async function callGroq() {
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.groq.com/openai/v1/chat/completions',
    headers: {
      'authorization': `Bearer ${GROQ}`,
      'content-type': 'application/json',
    },
    body: {
      model: 'llama-3.3-70b-versatile',
      max_tokens: 1500,
      temperature: 0.2,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: userPrompt },
      ],
    },
    json: true,
  });
  const text = r?.choices?.[0]?.message?.content || '';
  const usage = r?.usage || {};
  return { parsed: extractJson(text), provider: 'groq-llama-3.3-70b', tokens: { in: usage.prompt_tokens || 0, out: usage.completion_tokens || 0 }, raw: text };
}

async function callGemini() {
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${encodeURIComponent(GEMINI)}`,
    headers: { 'content-type': 'application/json' },
    body: {
      systemInstruction: { parts: [{ text: system }] },
      contents: [{ role: 'user', parts: [{ text: userPrompt }] }],
      generationConfig: { temperature: 0.2, maxOutputTokens: 1500, responseMimeType: 'application/json' },
    },
    json: true,
  });
  const text = (r?.candidates?.[0]?.content?.parts || []).map(p => p.text || '').join('\n').trim();
  const usage = r?.usageMetadata || {};
  return { parsed: extractJson(text), provider: 'gemini-2.0-flash', tokens: { in: usage.promptTokenCount || 0, out: usage.candidatesTokenCount || 0 }, raw: text };
}

async function callClaude() {
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': CLAUDE,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json',
    },
    body: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 1500,
      system,
      messages: [{ role: 'user', content: userPrompt }],
    },
    json: true,
  });
  const text = (r.content || []).map(c => c.text || '').join('\n').trim();
  const usage = r.usage || {};
  return { parsed: extractJson(text), provider: 'claude-haiku-4-5', tokens: { in: usage.input_tokens || 0, out: usage.output_tokens || 0 }, raw: text };
}

const ladder = [];
if (GROQ)   ladder.push({ name: 'groq',   fn: callGroq.bind(this) });
if (GEMINI) ladder.push({ name: 'gemini', fn: callGemini.bind(this) });
if (CLAUDE) ladder.push({ name: 'claude', fn: callClaude.bind(this) });

const attempts = [];
let result = null;
for (const step of ladder) {
  try {
    const out = await step.fn();
    if (out && out.parsed) { result = out; break; }
    attempts.push({ provider: step.name, error: 'invalid_json', raw: (out?.raw || '').slice(0, 200) });
  } catch (e) {
    attempts.push({ provider: step.name, error: (e && e.message) ? e.message.slice(0, 200) : 'unknown' });
  }
}

if (!result) {
  return [{ json: { ok: false, reason: 'all_providers_failed', attempts } }];
}

const parsed = result.parsed;
const rawActions = Array.isArray(parsed.actions) ? parsed.actions : [];
// monthlyKwh y IDs de catálogo NO son aplicables (RD-8). Los demás siguen el dominio del schema.
const allowedFields = new Set(['systemType','battQty','busVoltage','backupHours','autonomyDays','criticalPct','acometida','availableArea','wantsExcedentes']);

// Reglas duras de coherencia (servidor) — descartan actions inválidas aunque el modelo las devuelva.
const currentSysType = payload?.systemType;
const currentAcometida = payload?.acometida;
const currentBusVoltage = Number(payload?.busVoltage || 0);
const currentArea = Number(payload?.roof?.availableM2 || payload?.availableArea || 0) || null;
const currentWantsExcedentes = payload?.wantsExcedentes === true;
const monthlyKwh = Number(payload?.monthlyKwh || 0);
const monthlyProdKwh = Number(payload?.result?.monthlyProdKwh || 0);
const kwp = Number(payload?.result?.kwp || 0);
const coveragePct = monthlyKwh > 0 ? (monthlyProdKwh / monthlyKwh) * 100 : 0;
const hasSurplus = monthlyKwh > 0 && monthlyProdKwh > monthlyKwh;
const getCurrent = (field) => {
  if (field === 'availableArea') return currentArea;
  if (field === 'busVoltage') return currentBusVoltage;
  if (field === 'wantsExcedentes') return currentWantsExcedentes;
  if (field === 'acometida') return currentAcometida;
  if (field === 'systemType') return currentSysType;
  return payload?.[field] ?? payload?.backup?.[field] ?? null;
};
const acomRank = { monofasico: 1, bifasico: 2, trifasico: 3 };
const sanitizeAction = (a) => {
  if (!a || typeof a !== 'object' || !allowedFields.has(a.field)) return null;

  // RD-1: systemType — nunca cambiar desde off-grid; nunca on-grid undersized → hybrid.
  if (a.field === 'systemType') {
    if (currentSysType === 'off-grid') return null;
    if (currentSysType === 'on-grid' && a.value === 'hybrid' && coveragePct < 100) return null;
  }

  // RD-2: wantsExcedentes — solo si on-grid/hybrid Y hay excedentes reales.
  if (a.field === 'wantsExcedentes' && a.value === true) {
    if (currentSysType === 'off-grid') return null;
    if (!hasSurplus) return null;
  }

  // RD-3: availableArea — no reducir, no inflar irrealmente.
  if (a.field === 'availableArea') {
    const proposed = Number(a.value);
    if (!Number.isFinite(proposed) || proposed <= 0) return null;
    if (currentArea && proposed < currentArea) return null;
    if (proposed > 5000) return null; // valor irreal
  }

  // RD-4: dominio por systemType.
  if (['battQty','busVoltage'].includes(a.field) && currentSysType === 'on-grid') return null;
  if (['backupHours','criticalPct'].includes(a.field) && currentSysType !== 'hybrid') return null;
  if (a.field === 'autonomyDays' && currentSysType !== 'off-grid') return null;

  // RD-5: acometida — solo escala según potencia, nunca baja.
  if (a.field === 'acometida') {
    const proposed = a.value;
    const cur = currentAcometida;
    if (!acomRank[proposed]) return null;
    if (cur && acomRank[proposed] < acomRank[cur]) return null; // no baja
    if (proposed === 'trifasico' && kwp > 0 && kwp < 10) return null; // solo si la potencia lo exige
    if (proposed === 'monofasico' && currentSysType !== 'off-grid') return null; // residencial mínimo bifasico
  }

  // RD-6: busVoltage — solo subir según potencia.
  if (a.field === 'busVoltage') {
    const proposed = Number(a.value);
    if (![12,24,48].includes(proposed)) return null;
    if (currentBusVoltage && proposed < currentBusVoltage) return null; // no baja
    if (proposed === 12 && kwp >= 2) return null;
    if (proposed === 24 && kwp > 5) return null;
  }

  // RD-7: no proponer mismo valor.
  const cur = getCurrent(a.field);
  if (cur !== null && cur !== undefined) {
    const propStr = JSON.stringify(a.value);
    const curStr = JSON.stringify(cur);
    if (propStr === curStr) return null;
  }

  return { field: String(a.field), value: a.value, label: String(a.label || '').slice(0, 80), reason: String(a.reason || '').slice(0, 200) };
};
const actions = rawActions.map(sanitizeAction).filter(Boolean);

// Guardrail server-side para suggestions: si el usuario YA marcó wantsExcedentes:true,
// descarta sugerencias que re-propongan AGPE / inscripción / venta de excedentes. RD-2
// del prompt lo prohíbe pero Groq llama-3.3 a veces lo ignora con prompts largos.
// Patrón: mención de AGPE/inscripción/venta-excedentes Y verbo de acción (considerar/
// evaluar/inscribir/vender). No filtra menciones contextuales sin proponer hacer algo.
const rawSuggestions = Array.isArray(parsed.suggestions) ? parsed.suggestions : [];
const isAgpeReSuggestion = (s) => {
  if (typeof s !== 'string') return false;
  const t = s.toLowerCase();
  const mentionsAgpe = /agpe|inscrib|vender (excedentes|energ[ií]a)|venta de excedentes|programa de excedentes/.test(t);
  if (!mentionsAgpe) return false;
  return /considerar|evaluar|inscrib|vender|venta|implementar|investigar/.test(t);
};
const suggestions = (payload?.wantsExcedentes === true)
  ? rawSuggestions.filter(s => !isAgpeReSuggestion(s))
  : rawSuggestions;

return [{ json: {
  summary: parsed.summary || '',
  findings: Array.isArray(parsed.findings) ? parsed.findings : [],
  warnings: Array.isArray(parsed.warnings) ? parsed.warnings : [],
  suggestions,
  actions,
  provider: result.provider,
  tokens: result.tokens,
  attempts,
} }];
